CREATE OR REPLACE FUNCTION test.validate_json_schema(schema jsonb, data jsonb, root_schema jsonb DEFAULT NULL) RETURNS boolean AS $f$
DECLARE
  prop text;
  item jsonb;
  path text[];
  types text[];
  pattern text;
  props text[];
BEGIN
  IF root_schema IS NULL THEN
    root_schema = schema;
  END IF;

  IF schema ? 'type' THEN
    IF jsonb_typeof(schema->'type') = 'array' THEN
      types = ARRAY(SELECT jsonb_array_elements_text(schema->'type'));
    ELSE
      types = ARRAY[schema->>'type'];
    END IF;
    IF (SELECT NOT bool_or(public._validate_json_schema_type(type, data)) FROM unnest(types) type) THEN
      RETURN false;
    END IF;
  END IF;

  IF schema ? 'properties' THEN
    FOR prop IN SELECT jsonb_object_keys(schema->'properties') LOOP
      IF data ? prop AND NOT validate_json_schema(schema->'properties'->prop, data->prop, root_schema) THEN
        RETURN false;
      END IF;
    END LOOP;
  END IF;

  IF schema ? 'required' AND jsonb_typeof(data) = 'object' THEN
    IF NOT ARRAY(SELECT jsonb_object_keys(data)) @>
           ARRAY(SELECT jsonb_array_elements_text(schema->'required')) THEN
      RETURN false;
    END IF;
  END IF;

CREATE FUNCTION git_ls_tree_r(
    p_repo_id integer,
    p_tree_oid bytea,
    p_prefix text DEFAULT ''
)
RETURNS TABLE(mode text, path text, oid bytea, obj_type text)
LANGUAGE plpgsql STABLE AS $$
DECLARE
    v_content bytea;
    v_entry record;
BEGIN
    SELECT o.content INTO v_content
    FROM objects o
    WHERE o.repo_id = p_repo_id AND o.oid = p_tree_oid AND o.type = 2;

    IF v_content IS NULL THEN
        RETURN;
    END IF;

    FOR v_entry IN SELECT e.mode, e.name, e.entry_oid FROM git_tree_entries(v_content) e LOOP
        IF v_entry.mode = '40000' THEN
            path := p_prefix || v_entry.name || '/';
            mode := v_entry.mode;
            oid := v_entry.entry_oid;
            obj_type := 'tree';
            RETURN NEXT;

            RETURN QUERY SELECT * FROM git_ls_tree_r(p_repo_id, v_entry.entry_oid, p_prefix || v_entry.name || '/');
        ELSE
            path := p_prefix || v_entry.name;
            mode := v_entry.mode;
            oid := v_entry.entry_oid;
            obj_type := 'blob';
            RETURN NEXT;
        END IF;
    END LOOP;
END;
$$

-- Recursive tree walk
CREATE OR REPLACE FUNCTION git_ls_tree_r(
    p_repo_id integer,
    p_tree_oid bytea,
    p_prefix text DEFAULT ''
)
RETURNS TABLE(mode text, path text, oid bytea, obj_type text)
LANGUAGE plpgsql STABLE AS $$
DECLARE
    v_content bytea;
    v_entry record;
BEGIN
    SELECT o.content INTO v_content
    FROM objects o
    WHERE o.repo_id = p_repo_id AND o.oid = p_tree_oid AND o.type = 2;

    IF v_content IS NULL THEN
        RETURN;
    END IF;

    FOR v_entry IN SELECT e.mode, e.name, e.entry_oid FROM git_tree_entries(v_content) e LOOP
        IF v_entry.mode = '40000' THEN
            -- Directory: recurse
            path := p_prefix || v_entry.name || '/';
            mode := v_entry.mode;
            oid := v_entry.entry_oid;
            obj_type := 'tree';
            RETURN NEXT;

            RETURN QUERY SELECT * FROM git_ls_tree_r(p_repo_id, v_entry.entry_oid, p_prefix || v_entry.name || '/');
        ELSE
            path := p_prefix || v_entry.name;
            mode := v_entry.mode;
            oid := v_entry.entry_oid;
            obj_type := 'blob';
            RETURN NEXT;
        END IF;
    END LOOP;
END;
$$

CREATE OR REPLACE FUNCTION zanzibar_enumerate (p_subject text, p_relation text, p_object_namespace text, p_seen text[] DEFAULT '{}' ::text[])
  RETURNS TABLE (
    r_object_namespace text,
    r_object text,
    r_relation text,
    r_subject text)
  LANGUAGE plpgsql
AS $$
DECLARE
    rel text;
    var_r record;
BEGIN
    FOR var_r IN (
      SELECT
        object,
        object_namespace,
        relation,
        subject,
        subject_namespace,
        subject_relation
      FROM
        tuples
      WHERE
        subject = p_subject
      ORDER BY
        subject_relation NULLS FIRST)
      LOOP
        rel := var_r.object || '#' || var_r.relation;
        IF array_position(p_seen, rel) IS NULL THEN
            p_seen := array_append(p_seen, rel);
           IF var_r.object_namespace = p_object_namespace AND var_r.relation = p_relation THEN
              r_object_namespace := var_r.object_namespace;
              r_object := var_r.object;
              r_relation := var_r.relation;
              r_subject := var_r.subject;
              RETURN NEXT;
            ELSE
             RETURN QUERY SELECT * FROM zanzibar_enumerate (var_r.object, p_relation, p_object_namespace, p_seen);
            END IF;
        END IF;
      END LOOP;
END;
$$

-- AND: Bitwise AND with accumulator
CREATE OR REPLACE FUNCTION pg6502.op_and(p_mode TEXT, p_pc INT)
RETURNS VOID AS $$
DECLARE
    v_addr INT;
    v_val  INT;
    v_res  INT;
    v_size INT;
BEGIN
    CASE p_mode
        WHEN 'immediate'   THEN v_addr := pg6502.addr_immediate(p_pc);   v_size := 2;
        WHEN 'zero_page'   THEN v_addr := pg6502.addr_zero_page(p_pc);   v_size := 2;
        WHEN 'zero_page_x' THEN v_addr := pg6502.addr_zero_page_x(p_pc); v_size := 2;
        WHEN 'absolute'    THEN v_addr := pg6502.addr_absolute(p_pc);    v_size := 3;
        WHEN 'absolute_x'  THEN v_addr := pg6502.addr_absolute_x(p_pc);  v_size := 3;
        WHEN 'absolute_y'  THEN v_addr := pg6502.addr_absolute_y(p_pc);  v_size := 3;
        WHEN 'indirect_x'  THEN v_addr := pg6502.addr_indirect_x(p_pc);       v_size := 2;
        WHEN 'indirect_y'  THEN v_addr := pg6502.addr_indirect_y(p_pc);       v_size := 2;
    END CASE;

    v_val := pg6502.mem_read(v_addr);

    -- compute result explicitly
    SELECT a & v_val INTO v_res FROM pg6502.cpu;

    UPDATE pg6502.cpu
    SET a      = v_res,
        pc     = p_pc + v_size,
        flag_z = (v_res = 0),
        flag_n = ((v_res & 128) <> 0);
END;
$$ LANGUAGE plpgsql

-- ASL: Arithmetic Shift Left
CREATE OR REPLACE FUNCTION pg6502.op_asl(p_mode TEXT, p_pc INT)
RETURNS VOID AS $$
DECLARE v_addr INT; v_val INT; v_result INT; v_size INT;
BEGIN
    CASE p_mode
        WHEN 'accumulator' THEN
            SELECT a INTO v_val FROM pg6502.cpu;
            v_result := (v_val * 2) & 255;
            UPDATE pg6502.cpu SET a = v_result, pc = p_pc + 1;
        WHEN 'zero_page'   THEN v_addr := pg6502.addr_zero_page(p_pc);   v_size := 2;
        WHEN 'zero_page_x' THEN v_addr := pg6502.addr_zero_page_x(p_pc); v_size := 2;
        WHEN 'absolute'    THEN v_addr := pg6502.addr_absolute(p_pc);    v_size := 3;
        WHEN 'absolute_x'  THEN v_addr := pg6502.addr_absolute_x(p_pc);  v_size := 3;
    END CASE;

    IF p_mode != 'accumulator' THEN
        v_val := pg6502.mem_read(v_addr);
        v_result := (v_val * 2) & 255;
        PERFORM pg6502.mem_write(v_addr, v_result);
        UPDATE pg6502.cpu SET pc = p_pc + v_size;
    END IF;

    UPDATE pg6502.cpu SET
        flag_c = (v_val >= 128),
        flag_z = (v_result = 0),
        flag_n = ((v_result & 128) != 0);
END;
$$ LANGUAGE plpgsql

-- ROL: Rotate Left
CREATE OR REPLACE FUNCTION pg6502.op_rol(p_mode TEXT, p_pc INT)
RETURNS VOID AS $$
DECLARE v_addr INT; v_val INT; v_result INT; v_carry INT; v_size INT;
BEGIN
    SELECT CASE WHEN flag_c THEN 1 ELSE 0 END INTO v_carry FROM pg6502.cpu;

    CASE p_mode
        WHEN 'accumulator' THEN
            SELECT a INTO v_val FROM pg6502.cpu;
            v_result := ((v_val * 2) | v_carry) & 255;
            UPDATE pg6502.cpu SET a = v_result, pc = p_pc + 1;
        WHEN 'zero_page'   THEN v_addr := pg6502.addr_zero_page(p_pc);   v_size := 2;
        WHEN 'zero_page_x' THEN v_addr := pg6502.addr_zero_page_x(p_pc); v_size := 2;
        WHEN 'absolute'    THEN v_addr := pg6502.addr_absolute(p_pc);    v_size := 3;
        WHEN 'absolute_x'  THEN v_addr := pg6502.addr_absolute_x(p_pc);  v_size := 3;
    END CASE;

    IF p_mode != 'accumulator' THEN
        v_val := pg6502.mem_read(v_addr);
        v_result := ((v_val * 2) | v_carry) & 255;
        PERFORM pg6502.mem_write(v_addr, v_result);
        UPDATE pg6502.cpu SET pc = p_pc + v_size;
    END IF;

    UPDATE pg6502.cpu SET
        flag_c = (v_val >= 128),
        flag_z = (v_result = 0),
        flag_n = ((v_result & 128) != 0);
END;
$$ LANGUAGE plpgsql

-- ROR: Rotate Right
CREATE OR REPLACE FUNCTION pg6502.op_ror(p_mode TEXT, p_pc INT)
RETURNS VOID AS $$
DECLARE v_addr INT; v_val INT; v_result INT; v_carry INT; v_size INT;
BEGIN
    SELECT CASE WHEN flag_c THEN 1 ELSE 0 END INTO v_carry FROM pg6502.cpu;

    CASE p_mode
        WHEN 'accumulator' THEN
            SELECT a INTO v_val FROM pg6502.cpu;
            v_result := (v_val >> 1) | (v_carry * 128);
            UPDATE pg6502.cpu SET a = v_result, pc = p_pc + 1;
        WHEN 'zero_page'   THEN v_addr := pg6502.addr_zero_page(p_pc);   v_size := 2;
        WHEN 'zero_page_x' THEN v_addr := pg6502.addr_zero_page_x(p_pc); v_size := 2;
        WHEN 'absolute'    THEN v_addr := pg6502.addr_absolute(p_pc);    v_size := 3;
        WHEN 'absolute_x'  THEN v_addr := pg6502.addr_absolute_x(p_pc);  v_size := 3;
    END CASE;

    IF p_mode != 'accumulator' THEN
        v_val := pg6502.mem_read(v_addr);
        v_result := (v_val >> 1) | (v_carry * 128);
        PERFORM pg6502.mem_write(v_addr, v_result);
        UPDATE pg6502.cpu SET pc = p_pc + v_size;
    END IF;

    UPDATE pg6502.cpu SET
        flag_c = ((v_val & 1) = 1),
        flag_z = (v_result = 0),
        flag_n = ((v_result & 128) != 0);
END;
$$ LANGUAGE plpgsql

CREATE OR REPLACE FUNCTION "storage"."objects_update_prefix_trigger"()
    RETURNS trigger
AS $func$
DECLARE
    old_prefixes TEXT[];
BEGIN
    -- Ensure this is an update operation and the name has changed
    IF TG_OP = 'UPDATE' AND (NEW."name" <> OLD."name" OR NEW."bucket_id" <> OLD."bucket_id") THEN
        -- Retrieve old prefixes
        old_prefixes := "storage"."get_prefixes"(OLD."name");

        -- Remove old prefixes that are only used by this object
        WITH all_prefixes as (
            SELECT unnest(old_prefixes) as prefix
        ),
        can_delete_prefixes as (
             SELECT prefix
             FROM all_prefixes
             WHERE NOT EXISTS (
                 SELECT 1 FROM "storage"."objects"
                 WHERE "bucket_id" = OLD."bucket_id"
                   AND "name" <> OLD."name"
                   AND "name" LIKE (prefix || '%')
             )
         )
        DELETE FROM "storage"."prefixes" WHERE name IN (SELECT prefix FROM can_delete_prefixes);

        -- Add new prefixes
        PERFORM "storage"."add_prefixes"(NEW."bucket_id", NEW."name");
    END IF;
    -- Set the new level
    NEW."level" := "storage"."get_level"(NEW."name");

    RETURN NEW;
END;
$func$ LANGUAGE plpgsql VOLATILE

